import { setupTariffFree } from '@api/premium/setupTariffFree';
import { useState } from 'react';
import {
  deleteLocalStorageData,
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';

import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { SetupTariffFreeResponse } from '@api/urls';
import { logger } from '@utils/logger';
import { getDeviceId } from '@app/storage/utils/getDeviceId';
import { getDeviceIP } from '@app/storage/utils/getDeviceIP';
import { getMetaApiData } from '@utils/metaApiData';

type ErrorType = 'missingData' | 'api' | 'unknown';

export const useSetupTariffFree = () => {
  const [error, setError] = useState<ErrorType | null>(null);

  const becomeFreeUserHandler = async (): Promise<
    SetupTariffFreeResponse['data'] | null
  > => {
    try {
      const [deviceId, deviceIp, metaApiData, { userId }] = await Promise.all([
        getDeviceId(),
        getDeviceIP(),
        getMetaApiData(),
        getLocalStorageData([LocalStorageKey.UserId]),
      ]);

      if (!metaApiData || !deviceId || !deviceIp || !userId) {
        setError('missingData');
        return null;
      }
      const { apiBaseUrl } = metaApiData;

      const res = await setupTariffFree(apiBaseUrl, {
        deviceId,
        deviceIp,
        userId,
      });

      const data = res?.data;
      if (!data) {
        setError('api');
        return null;
      }

      const paymentStatus = await getLocalStorageData(LocalStorageKey.Status);
      await Promise.all([
        setLocalStorageData({
          [LocalStorageKey.HasPremium]: false,
          [LocalStorageKey.Status]: data?.subscription?.status || paymentStatus,
        }),
        deleteLocalStorageData(LocalStorageKey.PACPremiumData),
      ]);

      return data;
    } catch (error) {
      logger.error('useSetupTariffFree: error', error);
      setError('unknown');
      return null;
    }
  };

  return {
    becomeFreeUserHandler,
    error,
  };
};
