import i18n from 'i18next';
import { initReactI18next } from 'react-i18next';
import { setLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { isSupportedLanguage, resources, supportedLngs } from './languages';
import { getLanguageFromStorage } from '@app/i18n/utils';

const initialLanguage = await getLanguageFromStorage();

i18n.on('languageChanged', async (language) => {
  if (!isSupportedLanguage(language)) return;

  await setLocalStorageData({
    [LocalStorageKey.CurrentLocale]: language,
  });
});

i18n.use(initReactI18next).init({
  lng: initialLanguage,
  supportedLngs,
  fallbackLng: supportedLngs,
  debug: true,
  defaultNS: 'shared',
  resources,
});

export { supportedLngs, resources, isSupportedLanguage };
export default i18n;
