import React, { FC } from 'react';
import s from './PromoCodeActivated.module.css';
import { RoutePath } from '@popup/project/youboost/routes/types/RoutePath';
import { useTranslation, Trans } from 'react-i18next';
import { SecondaryWrapper } from '@popup/project/youboost/components/shared/SecondaryWrapper';
import { Button } from '@popup/project/youboost/components/shared/Button';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useFormattedDate } from '@popup/shared/hooks/useFormattedDate';
import { formatIntervalPeriod } from '@api/promoCodeCalculate';

interface Props {}

export const PromoCodeActivated: FC<Props> = ({}) => {
  const { t } = useTranslation('youboost', {
    keyPrefix: 'promo-code-activated-page',
  });
  const navigate = useNavigate();
  const { plural } = useFormattedDate();
  const [params] = useSearchParams();
  const interval = params.get('interval');

  const clickHandler = () => {
    navigate(RoutePath.Root);
  };

  const promoCodePeriod = formatIntervalPeriod(interval, plural);

  return (
    <SecondaryWrapper
      header={t('header')}
      footer={
        <Button size={'big'} color={'primary'} onClick={clickHandler}>
          {t('button')}
        </Button>
      }
      closeClickHandler={clickHandler}
    >
      <div className={s.body}>
        <div className={s.emoji}>🎉</div>
        <div className={s.title}>
          <Trans t={t} i18nKey="title" />
        </div>
        {interval && (
          <div className={s.description}>
            {t('description', { period: promoCodePeriod })}
          </div>
        )}
      </div>
    </SecondaryWrapper>
  );
};
