import { PluralFn } from '@api/promoCodeCalculate/types';
import dayjs from 'dayjs';
import { useCallback } from 'react';
import { useTranslation } from 'react-i18next';

type Case = 'nominative' | 'genitive' | 'prepositional';
type PluralKey = 'day' | 'month' | 'year' | 'hour' | 'minute' | 'second';

interface FormatOptions {
  case?: Case;
  pattern: string;
}

export const useFormattedDate = () => {
  const { t } = useTranslation('shared', {
    keyPrefix: 'date',
  });

  function getMonthName(
    monthIndex: number,
    grammaticalCase: Case = 'nominative',
  ) {
    return t(`month.${monthIndex}.${grammaticalCase}`);
  }

  const plural = useCallback<PluralFn>(
    (key: PluralKey, count: number, adj = '') => {
      const normalizedAdj = adj.trim();
      const translationKey = normalizedAdj
        ? `${key}_word.${key}_with_adj`
        : `${key}_word.${key}`;

      return t(translationKey, { count, adj: normalizedAdj });
    },
    [t],
  );

  function formatDateWithPattern(
    date: string | Date,
    { pattern, case: grammaticalCase = 'nominative' }: FormatOptions,
  ): string {
    const d = dayjs(date);

    const day = d.date();
    const monthIndex = d.month();
    const year = d.year();
    const hour = d.hour();
    const minute = d.minute();
    const second = d.second();

    const monthName = getMonthName(monthIndex, grammaticalCase);

    return pattern
      .replace('DD', String(day).padStart(2, '0'))
      .replace('MMMM', monthName)
      .replace('MM', String(monthIndex + 1).padStart(2, '0'))
      .replace('YYYY', String(year))
      .replace('YY', String(year).slice(-2))
      .replace('HH', String(hour).padStart(2, '0'))
      .replace('mm', String(minute).padStart(2, '0'))
      .replace('ss', String(second).padStart(2, '0'));
  }

  return {
    formatDateWithPattern,
    plural,
  };
};
