import { getCreateNewPaymentLinkUrl } from '@api/urls';
import {
  createNewPaymentLink,
  CreateNewPaymentLinkDto,
  PlatformType,
} from '@api/premium/createNewPaymentLink';
import { detectBrowser } from '@app/utils/detectBrowser';

export const getNewPaymentLink = async ({
  paymentMethod,
  url: apiBaseUrl,
  tariffName,
  userId,
  isAutoRenew,
  promocode,
}: Omit<CreateNewPaymentLinkDto, 'platform'>) => {
  const url = getCreateNewPaymentLinkUrl(apiBaseUrl);
  const browser = detectBrowser();
  const platform = PlatformType[browser];

  return await createNewPaymentLink({
    url,
    userId,
    tariffName,
    paymentMethod,
    isAutoRenew,
    platform,
    promocode,
  });
};
