import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { getIsPremiumStatus } from '@app/utils/getIsPremiumStatus';
import { GetSubscriptionResponse } from '@api/types';

export async function updateSubscriptionStorage(
  subscriptionInfo: GetSubscriptionResponse,
): Promise<void> {
  const isOnlyPremium: boolean = process.env.IS_ONLY_PREMIUM === 'true';

  const { daysLeft, paidUntil, status, secondsLeft, isAutoRenew, botDeepLink } =
    subscriptionInfo?.data?.subscription ?? {};

  const {
    name: currentTariff,
    deviceLimit,
    activeDevices,
  } = subscriptionInfo?.data?.tariff ?? {};

  const isPremiumStatus = getIsPremiumStatus(status);

  await setLocalStorageData({
    daysLeft,
    paidUntil,
    status,
    secondsLeft,
    currentTariff,
    deviceLimit,
    activeDevices,
    isAutoRenew,
    botDeepLink,
  });

  const { hasPremium, currentState } = await getLocalStorageData([
    LocalStorageKey.HasPremium,
    LocalStorageKey.CurrentState,
  ]);

  await setLocalStorageData({
    hasPremium: isOnlyPremium || isPremiumStatus,
  });

  if (status === 'Expired' && hasPremium && currentState === 'connected') {
    await setLocalStorageData({ targetState: 'disconnected' });
  }
}
