import { clsx } from 'clsx';
import { useNavigate } from 'react-router-dom';

import { DiscountPriceText } from '@popup/project/youboost/components/shared/DiscountPriceText';
import { Error } from '@popup/project/youboost/components/shared/errors/Error';
import { RoutePath } from '@popup/project/youboost/routes/types/RoutePath';
import { Trans, useTranslation } from 'react-i18next';
import { type CancelPage } from '../../types/CancelPage';
import { FooterButtons } from './FooterButtons/FooterButtons';
import { useFormatPrice } from '@popup/project/youboost/hooks/useFormatPrice';
import { useGetDiscountPrice } from '@popup/project/youboost/hooks/useGetDiscountPrice';

import styles from './Discount.module.css';

type DiscountProps = {
  page: CancelPage;
  handleCancelPremium: () => void;
};

export function Discount({
  page,
  handleCancelPremium,
}: DiscountProps): JSX.Element | null {
  const { t } = useTranslation('youboost', {
    keyPrefix: 'cancel-premium.discount',
  });
  const formatPrice = useFormatPrice();
  const navigate = useNavigate();

  const { price, discountPrice } = useGetDiscountPrice();
  const formattedPrice = formatPrice(price);
  const formattedDiscountPrice = formatPrice(discountPrice);

  return (
    <div
      className={clsx(styles.wrapper, {
        [styles['out']]: page !== 'discount',
      })}
      data-attribute="discount"
    >
      <Error
        title={t('title')}
        icon={<DiscountPriceText discountPrice={formattedDiscountPrice} />}
        subtitle={t('subtitle')}
        text={
          <Trans
            t={t}
            i18nKey="description"
            values={{
              price: formattedPrice,
              discountPrice: formattedDiscountPrice,
            }}
          />
        }
        footer={<FooterButtons onCancelPremium={handleCancelPremium} />}
        onClose={() => {
          navigate(RoutePath.Root);
        }}
      />
    </div>
  );
}
