import { FC } from 'react';
import s from './AuthBox.module.css';
import { useTranslation } from 'react-i18next';
import { Button } from '@popup/project/youboost/components/shared/Button';
import { QRCodeSVG } from 'qrcode.react';
import { Telegram } from '@popup/project/youboost/components/shared/icons';
import { setLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { browser_api } from '@app/browser_api';

interface Props {
  url: string;
  cancelHandler: () => Promise<void>;
}

export const AuthBox: FC<Props> = ({ url, cancelHandler }) => {
  const { t } = useTranslation('youboost', {
    keyPrefix: 'telegram-auth-promo-page',
  });

  const authHandler = async () => {
    await setLocalStorageData({ [LocalStorageKey.ShowTgAuthPopup]: true });
    await browser_api.tabs.create({ url });
  };

  return (
    <div className={s.body}>
      <div className={s.qr}>
        <QRCodeSVG
          value={url}
          size={102}
          bgColor={'transparent'}
          fgColor={'var(--telegram-promo-qr-code-color)'}
          title={url}
        />
      </div>
      <div className={s.right}>
        <div className={s.box}>
          <div className={s.title}>{t('label')}</div>
          <button
            className={s.subtitle}
            type={'button'}
            onClick={cancelHandler}
          >
            {t('no-tg')}
          </button>
        </div>

        <Button color={'secondary'} size={'small'} onClick={authHandler}>
          <Telegram />
          {t('auth-btn')}
        </Button>
      </div>
    </div>
  );
};
