import { FC } from 'react';
import { Button } from '@popup/project/youboost/components/shared/Button';
import { useTranslation } from 'react-i18next';
import s from './Footer.module.css';
import { RoutePath } from '@popup/project/youboost/routes/types/RoutePath';
import { useNavigate } from 'react-router-dom';
import { setLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';

interface Props {
  cancelHandler: () => Promise<void>;
}

export const Footer: FC<Props> = ({ cancelHandler }) => {
  const navigate = useNavigate();
  const { t } = useTranslation('youboost', {
    keyPrefix: 'telegram-auth-promo-page',
  });

  const loggedInHandler = async () => {
    await setLocalStorageData({ [LocalStorageKey.ShowTgAuthPopup]: true });
    navigate(RoutePath.Root, { replace: true });
  };

  return (
    <div className={s.buttons}>
      <Button color="primary" size="big" onClick={loggedInHandler}>
        {t('logged-in-btn')}
      </Button>
      <Button color="tertiary" size="default" onClick={cancelHandler}>
        {t('cancel-premium-btn')}
      </Button>
    </div>
  );
};
