import { httpClient } from '@api/httpClient';
import { CreateNewPaymentLinkDto, CreateNewPaymentLinkResponse } from './types';

export async function createNewPaymentLink({
  url,
  userId,
  tariffName,
  paymentMethod,
  isAutoRenew,
  platform,
  promocode,
}: CreateNewPaymentLinkDto): Promise<CreateNewPaymentLinkResponse> {
  const data = await httpClient
    .post<CreateNewPaymentLinkResponse>(url, {
      json: {
        userId,
        tariff: tariffName,
        paymentMethod,
        isAutoRenew,
        platform,
        promocode,
      },
    })
    .json();
  return data;
}
