import { create } from 'zustand';
import { BridgeStoreStateType } from '../types';
import { browser_api } from '@app/browser_api';
import { defaultState, StoreMessageActions } from '../shared';
import { isStoreMessageOfType, postMessageHandler } from '../utils';
import { LocalStorageData } from '@app/storage/local/types/sharedTypes';

let port = browser_api.runtime.connect({ name: 'bridge' });
let reconnectTimeout: NodeJS.Timeout | null = null;

const reconnectPort = () => {
  if (reconnectTimeout) {
    clearTimeout(reconnectTimeout);
  }

  reconnectTimeout = setTimeout(() => {
    try {
      port = browser_api.runtime.connect({ name: 'bridge' });
      setupPortListeners();
    } catch (error) {
      reconnectPort();
    }
  }, 1000);
};

// Настройка слушателей порта
const setupPortListeners = () => {
  port.onMessage.addListener((msg) => {
    if (isStoreMessageOfType(msg, StoreMessageActions.STATE)) {
      bridgeStore.setState(
        () => ({ ...msg.payload, setData, resetData, removeData }),
        true,
      );
    }
  });

  port.onDisconnect.addListener(() => {
    reconnectPort();
  });
};

const setData = (data: LocalStorageData) => {
  const success = postMessageHandler(port, StoreMessageActions.SET, data);
  if (!success) {
    reconnectPort();
  }
};

const resetData = () => {
  const success = postMessageHandler(
    port,
    StoreMessageActions.RESET,
    undefined,
  );
  if (!success) {
    reconnectPort();
  }
};

const removeData = (keys: Array<keyof LocalStorageData>) => {
  const success = postMessageHandler(port, StoreMessageActions.REMOVE, keys);
  if (!success) {
    reconnectPort();
  }
};

export const bridgeStore = create<BridgeStoreStateType>(() => {
  return {
    ...defaultState,
    setData,
    resetData,
    removeData,
  };
});

export const useBridgeStore = bridgeStore;

// Инициализация слушателей порта
setupPortListeners();
