import { getMetaApiData } from '@utils/metaApiData';
import {
  fetchSubscriptionInfo,
  type SubscriptionInfoError,
} from '@api/premium/fetchPremiumData';
import { Actions } from '@app/actions/shared';
import { browser_api } from '@app/browser_api';
import {
  getLocalStorageData,
  setLocalStorageData,
} from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { getDeviceId } from '@app/storage/utils/getDeviceId';
import { getDeviceIP } from '@app/storage/utils/getDeviceIP';
import { getIsPremiumStatus } from '@app/utils/getIsPremiumStatus';
import { GetSubscriptionResponse } from '@api/types';
import { logger } from '@utils/logger';
import { messageDispatcher } from '@app/infrastructure/messageDispatcher';

function isGetSubscriptionInfoError(
  data: GetSubscriptionResponse | SubscriptionInfoError,
): data is SubscriptionInfoError {
  return 'error' in data && data.error !== null;
}

import { updateSubscriptionStorage } from './subscription/updateSubscriptionStorage';

export async function getSubscriptionInfo(): Promise<GetSubscriptionResponse | null> {
  // TODO убрать костыль проверки расширения из shared ( process.env.EXTENSION_CODE )
  if (process.env.EXTENSION_CODE === 'naruzhuv2') {
    return null;
  }

  try {
    await setLocalStorageData({
      [LocalStorageKey.IsSubscriptionInfoError]: false,
    });

    const { apiBaseUrl } = await getMetaApiData();

    const deviceId = await getDeviceId();
    const deviceIp = await getDeviceIP();

    const { userId } = await getLocalStorageData(LocalStorageKey.UserId);

    const subscriptionInfo = await fetchSubscriptionInfo(apiBaseUrl, {
      userId,
      deviceId,
      deviceIp,
    });

    if (isGetSubscriptionInfoError(subscriptionInfo)) {
      if (subscriptionInfo.error === 'changeDevice') {
        await setLocalStorageData({
          [LocalStorageKey.IsChangeDeviceError]: true,
        });

        await setLocalStorageData({
          [LocalStorageKey.TargetState]: 'disconnected',
        });

        try {
          await messageDispatcher.send({
            action: Actions.OpenPopupChangeDevice,
          });
        } catch (error) {
          logger.error('getSubscriptionInfo: error', error);
        }

        return null;
      }

      if (subscriptionInfo.error === 'requestBlockedError') {
        await setLocalStorageData({
          [LocalStorageKey.RequestBlockedError]:
            'request fetchSubscriptionInfo is probably blocked',
        });
      }

      throw new Error(subscriptionInfo.error);
    }

    await updateSubscriptionStorage(subscriptionInfo);

    return subscriptionInfo;
  } catch (error) {
    logger.error('getSubscriptionInfo: error', error);

    if (error instanceof Error && error.message === 'userNotFound') {
      throw error;
    }

    await setLocalStorageData({ isSubscriptionInfoError: true });
    return null;
  }
}
