import { RoutePath } from '@popup/project/youboost/routes/types/RoutePath';
import { Trans, useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { useGetDiscountPrice } from '@popup/project/youboost/hooks/useGetDiscountPrice';
import { DiscountPriceText } from '../../shared/DiscountPriceText';
import { Error } from '../../shared/errors/Error';
import { FooterButtons } from './FooterButtons/FooterButtons';
import { useSetupTariffFree } from '@popup/shared/hooks/useSetupTariffFree';
import { logger } from '@utils/logger';
import { useFormatPrice } from '@popup/project/youboost/hooks/useFormatPrice';

export const PremiumSalePersuasionContent = () => {
  const { t } = useTranslation('youboost', {
    keyPrefix: 'premium-sale-persuasion',
  });
  const { t: tError } = useTranslation('youboost', {
    keyPrefix: 'telegram-auth-promo-page.error',
  });
  const formatPrice = useFormatPrice();
  const { becomeFreeUserHandler, error } = useSetupTariffFree();
  const { price, discountPrice } = useGetDiscountPrice();
  const navigate = useNavigate();

  const formattedPrice = formatPrice(price);
  const formattedDiscountPrice = formatPrice(discountPrice);

  const cancelHandler = async () => {
    try {
      const data = await becomeFreeUserHandler();
      if (data) {
        navigate(RoutePath.Root, { replace: true });
      }
    } catch (e) {
      logger.error('PremiumSalePersuasionContent: error', e);
    }
  };

  if (error) {
    return (
      <Error
        text={tError(error)}
        onClose={() => {
          navigate(RoutePath.Root);
        }}
      />
    );
  }

  return (
    <Error
      title={t('title')}
      icon={<DiscountPriceText discountPrice={formattedDiscountPrice} />}
      subtitle={t('subtitle')}
      text={
        <Trans
          t={t}
          i18nKey="description"
          values={{
            price: formattedPrice,
            discountPrice: formattedDiscountPrice,
          }}
        />
      }
      footer={<FooterButtons cancelHandler={cancelHandler} />}
      onClose={() => {
        navigate(RoutePath.Root);
      }}
    />
  );
};
