import { useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { useLocalStorage } from '@popup/shared/hooks/useLocalStorage';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import {
  parseRate,
  roundToHundredths,
  formatNumericPrice,
} from '@popup/shared/utils/currencyConversion';

const LOADING_PLACEHOLDER = '...';

export const useFormatPrice = (): ((price: number) => string) => {
  const { t, i18n } = useTranslation('youboost', { keyPrefix: 'common' });
  const currentLocale = i18n.language;
  const [rates] = useLocalStorage(
    LocalStorageKey.ExchangeRatesCache,
    undefined,
  );

  const formatPrice = useCallback(
    (price: number): string => {
      if (currentLocale === 'ru') {
        return t('price', {
          price: formatNumericPrice(price),
        });
      }

      if (!rates) return LOADING_PLACEHOLDER;

      const euroRate = parseRate(rates.eur);
      const convertedPrice = roundToHundredths(price / euroRate);

      return t('price', {
        price: convertedPrice,
      });
    },
    [currentLocale, rates, t],
  );

  return formatPrice;
};
