import { httpClient } from '@api/httpClient';
import { getPromoCodeCalculateApiUrl } from '@api/urls';
import { getMetaApiData } from '@utils/metaApiData';
import {
  PromoCodeCalculateResponseType,
  PromoCodeCalculateType,
} from './types';
import { HTTPError } from 'ky';

export const promoCodeCalculate: PromoCodeCalculateType = async (body) => {
  try {
    const { apiBaseUrl } = await getMetaApiData();
    const url = getPromoCodeCalculateApiUrl(apiBaseUrl);
    return await httpClient
      .post<PromoCodeCalculateResponseType>(url, {
        json: body,
      })
      .json();
  } catch (e) {
    if (e instanceof HTTPError) {
      return await e.response.json<
        Extract<PromoCodeCalculateResponseType, { data: null }>
      >();
    }
    return {
      data: null,
      error: { code: 'unknown', localized_message: 'Unknown error' },
    };
  }
};
