import { Dispatch, FC, SetStateAction } from 'react';
import { TabItem } from '@popup/project/youboost/components/shared/Tabs';
import {
  PaymentMethod,
  PaymentMethodV2Type,
} from '@app/features/types/paymentMethodTypes';
import { MethodItem } from '@popup/project/youboost/components/PaymentContent/ui/MethodItem/MethodItem';
import styles from './SelectMethod.module.css';

interface Props {
  availablePaymentMethods: PaymentMethodV2Type[];
  setSelectedPaymentMethod: Dispatch<SetStateAction<PaymentMethodV2Type>>;
  selectedPaymentMethod: PaymentMethodV2Type;
}

const getPaymentsItems = ({
  availablePaymentMethods,
}: {
  availablePaymentMethods: PaymentMethodV2Type[];
}): TabItem<PaymentMethod>[] => {
  return availablePaymentMethods.map(({ type: method }) => {
    const id = method;
    return {
      id,
      label: <MethodItem method={method} />,
      content: null,
      dataTestId: id,
    };
  });
};

export const SelectMethod: FC<Props> = ({
  availablePaymentMethods,
  setSelectedPaymentMethod,
  selectedPaymentMethod,
}) => {
  const paymentsItems = getPaymentsItems({
    availablePaymentMethods,
  });

  return (
    <div className={styles.container}>
      {paymentsItems.map((item) => {
        return (
          <label className={styles.label} key={item.id}>
            <input
              data-testid={item.dataTestId}
              type="radio"
              name="PaymentMethodGroup"
              value={item.id}
              checked={selectedPaymentMethod.type === item.id}
              onChange={() => {
                const paymentMethod = availablePaymentMethods.find(
                  ({ type }) => type === item.id,
                )!;
                setSelectedPaymentMethod(paymentMethod);
              }}
            />
            {item.label}
            <span className={styles['check-mark']}></span>
          </label>
        );
      })}
    </div>
  );
};
