import { FC } from 'react';
import { useTranslation } from 'react-i18next';
import { TariffData } from '@api/urls';
import { getTariffLocaleKey } from '@popup/project/youboost/components/TariffsContent/utils';
import { Tag } from '@popup/project/youboost/components/shared/Tag/ui/Tag';
import { clsx } from 'clsx';
import { defaultTariffName } from '@popup/project/youboost/components/TariffsContent/constants';
import { useFormatPrice } from '@popup/project/youboost/hooks/useFormatPrice';

import s from './TariffItem.module.css';

interface Props extends TariffData {
  hasOneMonthDiscount: boolean;
  isAccent?: boolean;
  discountPrice?: number;
}

export const TariffItem: FC<Props> = ({
  price,
  tariff,
  period,
  monthPrice,
  hasOneMonthDiscount,
  isAccent = false,
  discountPrice,
}) => {
  const { t } = useTranslation('youboost', {
    keyPrefix: 'tariffs-page.periods',
  });
  const formatPrice = useFormatPrice();

  // TODO We need to rewrite this part of the code after backend implementation - https://vpnn.youtrack.cloud/issue/FRO-577
  const isDiscountTariff = tariff === defaultTariffName;
  const discountPriceValue =
    isDiscountTariff && hasOneMonthDiscount ? discountPrice : undefined;
  const formattedSum = formatPrice(price);
  const formattedDiscountPriceValue = discountPriceValue
    ? formatPrice(discountPriceValue)
    : undefined;
  const formattedMonthPrice = formatPrice(monthPrice);

  return (
    <div className={s.item}>
      <div className={s.left}>
        <div className={s.price}>
          {typeof discountPriceValue === 'undefined' ? (
            formattedSum
          ) : (
            <>
              {formattedDiscountPriceValue}
              <span className={clsx(s.label, s.old)}>{formattedSum}</span>
            </>
          )}{' '}
          {isAccent && (
            <span className={s.label}>
              {formattedMonthPrice}/{t('month')}
            </span>
          )}
        </div>
        <div className={s.label}>
          {t(getTariffLocaleKey(tariff), {
            defaultValue: period,
          })}
        </div>
      </div>
      <div className={s.right}>
        <div className={clsx(s.label, isAccent && s.accent)}>
          {isAccent ? (
            <Tag>{t('accent-offer')}</Tag>
          ) : (
            <>{`${discountPriceValue ? formattedDiscountPriceValue : formattedMonthPrice}/${t('month')}`}</>
          )}
        </div>
      </div>
    </div>
  );
};
