import React, { FC, useRef, useState } from 'react';
import { Tariff } from '@api/premium/types/Tariff';
import { useLocation, useNavigate } from 'react-router-dom';
import { SecondaryWrapper } from '@popup/project/youboost/components/shared/SecondaryWrapper';
import { useTranslation } from 'react-i18next';
import { PaymentMethodV2Type } from '@app/features/types/paymentMethodTypes';
import { RoutePath } from '@popup/project/youboost/routes/types/RoutePath';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { Footer } from '@popup/project/youboost/components/PaymentContent/ui/Footer/Footer';
import { useLocalStorage } from '@popup/shared/hooks/useLocalStorage';
import { defaultTariffName } from '@popup/project/youboost/components/TariffsContent';
import { Error } from '@popup/project/youboost/components/shared/errors/Error';
import {
  Body,
  usePaymentScreen,
} from '@popup/project/youboost/components/PaymentContent';
import { TariffData } from '@api/urls';
import {
  isSuccessResponse,
  PromoCodeCalculateResponseType,
} from '@api/promoCodeCalculate/types';
import { normalizeMoney } from '@utils/normalizeMoney';
import { getPromoFlags } from '@api/promoCodeCalculate/utils';
import { useFormatPrice } from '@popup/project/youboost/hooks/useFormatPrice';

type StateType =
  | {
      discountPrice: number;
      selectedTariff?: TariffData;
      hasOneMonthDiscount?: boolean;
      prevRoute?: string;
    }
  | undefined;

interface Props {}

export const Payment: FC<Props> = () => {
  const { t, i18n } = useTranslation('youboost', { keyPrefix: 'payment-page' });
  const navigate = useNavigate();
  const location = useLocation();
  const selectedPaymentMethodRef = useRef<PaymentMethodV2Type | null>(null);
  const renewalEnabledRef = useRef<boolean>(false);
  const [hasPremium] = useLocalStorage(LocalStorageKey.HasPremium);
  const [metaApiData] = useLocalStorage(LocalStorageKey.MetaApiData);

  const { error, availablePaymentMethods, publicOfferUrl, onPaymentClick } =
    usePaymentScreen();
  const [promoCodeCalculateResponse, setPromoCodeCalculateResponse] =
    useState<PromoCodeCalculateResponseType | null>(null);
  const formatPrice = useFormatPrice();

  const state = location.state as StateType;
  const extend = Boolean(hasPremium);
  const selectedTariff = state?.selectedTariff;
  const hasOneMonthDiscount = Boolean(state?.hasOneMonthDiscount);
  const prevRoute = state?.prevRoute ?? RoutePath.Root;

  const discountPrice = isSuccessResponse(promoCodeCalculateResponse)
    ? normalizeMoney(promoCodeCalculateResponse.data.details.total_to_pay)
    : state?.discountPrice;

  if (error) return <Error />;
  if (!selectedTariff || !publicOfferUrl) return null;

  const { isPercentDiscount, isFreeUsageGift } = getPromoFlags(
    promoCodeCalculateResponse,
  );
  const isPromoCodeDiscount = isPercentDiscount || isFreeUsageGift;

  const isOneMonthDiscount =
    selectedTariff.tariff === defaultTariffName && hasOneMonthDiscount;

  const isDiscount =
    (isOneMonthDiscount || isPromoCodeDiscount) &&
    typeof discountPrice === 'number';

  const tariffData = {
    ...selectedTariff,
    // TODO We need to rewrite this part of the code after backend implementation - https://vpnn.youtrack.cloud/issue/FRO-577
    tariff: isPromoCodeDiscount
      ? selectedTariff.tariff
      : isOneMonthDiscount
        ? Tariff.Discount
        : selectedTariff.tariff,
    price: isDiscount ? discountPrice : selectedTariff.price,
    oldPrice: isDiscount ? selectedTariff.price : undefined,
  };

  const closeClickHandler = () => {
    navigate(RoutePath.Root);
  };

  return (
    <SecondaryWrapper
      header={t(extend ? 'title-payment-method' : 'title-buy')}
      footer={
        <Footer
          {...tariffData}
          publicOfferUrl={publicOfferUrl}
          selectedPaymentMethodRef={selectedPaymentMethodRef}
          renewalEnabledRef={renewalEnabledRef}
          handlePaymentClick={onPaymentClick}
          promoCodeCalculateResponse={promoCodeCalculateResponse}
        />
      }
      backButtonProps={{
        onClick: () =>
          navigate(RoutePath.Tariffs, {
            state: { hasOneMonthDiscount, prevRoute },
          }),
      }}
      closeClickHandler={closeClickHandler}
    >
      <Body
        renewalEnabledRef={renewalEnabledRef}
        selectedPaymentMethodRef={selectedPaymentMethodRef}
        availablePaymentMethods={availablePaymentMethods}
        hasOneMonthDiscount={hasOneMonthDiscount}
        setPromoCodeCalculateResponse={setPromoCodeCalculateResponse}
        promoCodeCalculateResponse={promoCodeCalculateResponse}
        {...tariffData}
      />
    </SecondaryWrapper>
  );
};
