import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { logger } from '@utils/logger';
import type { SupportedLanguages } from '@app/i18n';

export async function getLanguageFromStorage(): Promise<
  SupportedLanguages | undefined
> {
  try {
    const { currentLocale } = await getLocalStorageData([
      LocalStorageKey.CurrentLocale,
    ]);
    return currentLocale;
  } catch (error) {
    logger.info('Failed to get language from storage:', error);
    return;
  }
}
