import type { Dispatch, FC, MutableRefObject, SetStateAction } from 'react';
import { useEffect, useState } from 'react';
import { SelectMethod } from '@popup/project/youboost/components/PaymentContent/ui/SelectMethod/SelectMethod';
import { useTranslation } from 'react-i18next';
import { PaymentMethodV2Type } from '@app/features/types/paymentMethodTypes';
import { getTariffLocaleKey } from '@popup/project/youboost/components/TariffsContent/utils';
import { TariffData } from '@api/urls';
import { RenewalRow } from '@popup/project/youboost/components/PaymentContent/ui/RenewalRow/RenewalRow';
import { useFormatPrice } from '@popup/project/youboost/hooks/useFormatPrice';
import s from './Body.module.css';
import { useFeaturesList } from '@app/features/hooks/useFeaturesList';
import { Feature } from '@app/features/types/Feature';
import { clsx } from 'clsx';
import { PromoCode } from '@popup/project/youboost/components/PaymentContent/ui/PromoCode/PromoCode';
import { PromoCodeCalculateResponseType } from '@api/promoCodeCalculate/types';
import { useFormattedDate } from '@popup/shared/hooks/useFormattedDate';
import { formatIntervalPeriod, getPromoFlags } from '@api/promoCodeCalculate';

interface Props extends TariffData {
  availablePaymentMethods: PaymentMethodV2Type[];
  hasOneMonthDiscount: boolean;
  selectedPaymentMethodRef: MutableRefObject<PaymentMethodV2Type | null>;
  renewalEnabledRef: MutableRefObject<boolean>;
  oldPrice?: number;
  promoCodeCalculateResponse: PromoCodeCalculateResponseType | null;
  setPromoCodeCalculateResponse: Dispatch<
    SetStateAction<PromoCodeCalculateResponseType | null>
  >;
}

export const Body: FC<Props> = ({
  availablePaymentMethods,
  deviceLimit,
  period,
  tariff,
  price,
  oldPrice,
  selectedPaymentMethodRef,
  renewalEnabledRef,
  promoCodeCalculateResponse,
  setPromoCodeCalculateResponse,
}) => {
  const { t } = useTranslation('youboost', { keyPrefix: 'payment-page' });
  const { t: tTariff } = useTranslation('youboost', {
    keyPrefix: 'tariffs-page',
  });
  const formatPrice = useFormatPrice();

  const { plural } = useFormattedDate();
  const { featuresList } = useFeaturesList();
  const [renewalEnabled, setRenewalEnabled] = useState(false);
  const [selectedPaymentMethod, setSelectedPaymentMethod] =
    useState<PaymentMethodV2Type>(availablePaymentMethods[0]);

  useEffect(() => {
    selectedPaymentMethodRef.current = selectedPaymentMethod;
  }, [selectedPaymentMethod, selectedPaymentMethodRef]);

  useEffect(() => {
    renewalEnabledRef.current = renewalEnabled;
  }, [renewalEnabled, renewalEnabledRef]);

  const renewalToggler = () => {
    setRenewalEnabled((prev) => !prev);
  };

  const isFeatureEnabled = featuresList[Feature.AutoRenewal];
  const isAutoRenewVisible =
    isFeatureEnabled && selectedPaymentMethod.supportsAutoRenew;

  const { isFreeUsageGift } = getPromoFlags(promoCodeCalculateResponse);
  const promoCodePeriod = formatIntervalPeriod(
    promoCodeCalculateResponse?.data?.details?.promocode?.interval,
    plural,
  );

  return (
    <div className={s.box}>
      <div className={s.wrapper}>
        <div className={clsx(s.body, isFreeUsageGift && s.notAllowed)}>
          <div className={s.header}>
            <div className={s.title}>{t('select-method-title')}</div>
            <div className={s.description}>
              {t('select-method-description')}
            </div>
          </div>
          <div className={s.methods}>
            <SelectMethod
              setSelectedPaymentMethod={setSelectedPaymentMethod}
              selectedPaymentMethod={selectedPaymentMethod}
              availablePaymentMethods={availablePaymentMethods}
            />
          </div>
          <div className={s.main}>
            {isAutoRenewVisible ? (
              <RenewalRow
                clickHandler={renewalToggler}
                enabled={renewalEnabled}
              />
            ) : (
              <div className={s.empty} />
            )}
          </div>
        </div>
        <PromoCode
          tariff={tariff}
          setPromoCodeCalculateResponse={setPromoCodeCalculateResponse}
        />
      </div>
      <div className={s.footer}>
        <div className={s.info}>
          {isFreeUsageGift ? (
            t('info.free-usage-title', { period: promoCodePeriod })
          ) : (
            <>
              {t('info.title')}
              <div>
                {tTariff(`periods.${getTariffLocaleKey(tariff)}`, {
                  defaultValue: period,
                })}
                , {t('info.browser', { count: deviceLimit })}
              </div>
            </>
          )}
        </div>
        <div className={clsx(s.amount, oldPrice && s.discount)}>
          {oldPrice && !isFreeUsageGift && <span>{formatPrice(oldPrice)}</span>}
          {formatPrice(price)}
        </div>
      </div>
    </div>
  );
};
