import { FC, useEffect, useState } from 'react';
import { PopupWrapper } from '@popup/project/youboost/components/shared/PopupWrapper/PopupWrapper';
import { Button } from '@popup/project/youboost/components/shared/Button';
import { useTranslation } from 'react-i18next';
import { getSubscriptionInfo } from '@utils/getSubscriptionInfo';
import {
  deleteLocalStorageData,
  getLocalStorageData,
} from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';

interface Props {}

export const TgAuthPopup: FC<Props> = ({}) => {
  const { t } = useTranslation('youboost', {
    keyPrefix: 'tg-auth-popup',
  });
  const [isOpen, setIsOpen] = useState(false);
  const closeHandler = async () => {
    try {
      await getSubscriptionInfo();
    } catch (e) {
    } finally {
      await deleteLocalStorageData([LocalStorageKey.ShowTgAuthPopup]);
      setIsOpen(false);
    }
  };

  useEffect(() => {
    getLocalStorageData([LocalStorageKey.ShowTgAuthPopup]).then(
      ({ showTgAuthPopup }) => {
        setIsOpen(Boolean(showTgAuthPopup));
      },
    );
  }, []);

  if (!isOpen) return null;

  return (
    <PopupWrapper
      footer={
        <Button color={'primary'} size={'default'} onClick={closeHandler}>
          {t('btn-text')}
        </Button>
      }
      onClose={closeHandler}
    >
      <h3>{t('title')}</h3>
    </PopupWrapper>
  );
};
