import { type Resource, ResourceLanguage } from 'i18next';
import en from '@locales/en';
import ru from '@locales/ru';
import pl from '@locales/pl';
import es from '@locales/es';
import pt from '@locales/pt';
import de from '@locales/de';
import fr from '@locales/fr';
import tr from '@locales/tr';
import it from '@locales/it';
import { getSupportedLanguages } from './getSupportedLanguages';
import { ContextType } from '@app/i18n/types';
import { featureStore } from '@app/features/list';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { FeatureList } from '@app/features/types/Feature';

const LANG_RESOURCES: Record<string, ResourceLanguage> = {
  ru,
  en,
  pl,
  es,
  pt,
  de,
  fr,
  tr,
  it,
};

export async function getI18nConfig(context: ContextType) {
  let featureList: Partial<FeatureList> | null = null;
  if (context === 'background') {
    const snapshot = await featureStore.getSnapshotAsync();
    featureList = snapshot.featuresList;
  } else {
    const { featuresListLocal, featureStore } = await getLocalStorageData([
      LocalStorageKey.FeaturesListLocal,
      LocalStorageKey.FeatureStore,
    ]);
    featureList = {
      ...featureStore?.featuresList,
      ...featuresListLocal,
    };
  }

  const supportedLngs = await getSupportedLanguages(featureList);
  const resources = supportedLngs.reduce((acc, lang) => {
    acc[lang] = LANG_RESOURCES[lang];
    return acc;
  }, {} as Resource);

  return { supportedLngs, resources };
}
