import { browser_api } from "@app/browser_api";
import { getLocalStorageData, setLocalStorageData } from "@app/storage/local/shared";
import { LocalStorageKey } from "@app/storage/local/types/sharedTypes";
import { useEffect, useState } from "react";

export const useCustomApiUrl = () => {
  const [customApiUrl, setCustomApiUrl] = useState('');
  const [isError, setIsError] = useState(false);

  useEffect(() => {
    const getStoredCustomApiUrl = async () => {
      const { customApiUrl } = await getLocalStorageData(LocalStorageKey.CustomApiUrl);
      setCustomApiUrl(customApiUrl || '');
    }
    void getStoredCustomApiUrl();
  }, []);

  const applyCustomApiUrl = async () => {
    setIsError(false);
    const trimmedApiUrl = customApiUrl.trim();

    const domainPattern =
      /^(?=.{1,253}$)(?:[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?\.)+[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?$/i;

    if (!domainPattern.test(trimmedApiUrl)) {
      setIsError(true);
      return;
    }

    await setLocalStorageData({ [LocalStorageKey.CustomApiUrl]: trimmedApiUrl });
    browser_api.runtime.reload();
  }

  const resetCustomApiUrl = async () => {
    await setLocalStorageData({ [LocalStorageKey.CustomApiUrl]: '' });
    browser_api.runtime.reload();
  }

  return {
    customApiUrl,
    isError,
    setCustomApiUrl,
    applyCustomApiUrl,
    resetCustomApiUrl,
  }
}