export const roundToHundredths = (value: number): number => {
  return Math.round(value * 100) / 100;
};

export const formatNumericPrice = (price: number): number => {
  return Number.isInteger(price) ? price : roundToHundredths(price);
};

export const parseRate = (rate: string): number => {
  const parsed = parseFloat(rate);
  return isNaN(parsed) ? 0 : parsed;
};
