import {
  type ChangeEvent,
  type Dispatch,
  FC,
  type SetStateAction,
  useState,
} from 'react';
import s from './PromoCode.module.css';
import { Input } from '@popup/project/youboost/components/shared/Input';
import { Button } from '@popup/project/youboost/components/shared/Button';
import { useTranslation } from 'react-i18next';
import { useFormattedDate } from '@popup/shared/hooks/useFormattedDate';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { logger } from '@utils/logger';
import { type Tariff } from '@api/premium/types/Tariff';
import {
  isSuccessResponse,
  promoCodeCalculate,
  formatIntervalPeriod,
  getPromoFlags,
  type PromoCodeCalculateResponseType,
} from '@api/promoCodeCalculate';
import { HTTPError } from 'ky';

interface Props {
  tariff: Tariff;
  setPromoCodeCalculateResponse: Dispatch<
    SetStateAction<PromoCodeCalculateResponseType | null>
  >;
}

type PromoCodeStatusType = { type: 'success' | 'error'; text: string };

const getPromoCodeType = ({
  isFreeUsageGift,
  isExtraDays,
}: {
  isFreeUsageGift: boolean;
  isExtraDays: boolean;
}) =>
  isFreeUsageGift
    ? 'subscription-bonus'
    : isExtraDays
      ? 'extra-days'
      : 'applied';

export const PromoCode: FC<Props> = ({
  tariff,
  setPromoCodeCalculateResponse,
}) => {
  const { t } = useTranslation('youboost', {
    keyPrefix: 'payment-page.promo-code-section',
  });
  const { plural } = useFormattedDate();
  const [isInputVisible, setIsInputVisible] = useState(false);
  const [value, setValue] = useState('');
  const [status, setStatus] = useState<PromoCodeStatusType | null>(null);

  const isDisabledButton = !value.trim() || status !== null;

  const showInputHandler = () => {
    setIsInputVisible(true);
  };

  const checkPromoHandler = async () => {
    try {
      if (isDisabledButton) return;
      const promocode = value.trim();
      const { userId } = await getLocalStorageData(LocalStorageKey.UserId);
      if (!userId) {
        setStatus({
          type: 'error',
          text: t('input.error.user-is-not-defined'),
        });
        return;
      }
      const response = await promoCodeCalculate({ promocode, userId, tariff });
      setPromoCodeCalculateResponse(response);
      if (isSuccessResponse(response)) {
        const detailsData = response.data.details;
        const promoCodeData = detailsData.promocode;
        if (!promoCodeData) return;
        const { isExtraDays, isFreeUsageGift } = getPromoFlags(response);
        const promoCodePeriod = formatIntervalPeriod(
          response?.data?.details?.promocode?.interval,
          plural,
        );
        const type = getPromoCodeType({ isExtraDays, isFreeUsageGift });
        setStatus({
          type: 'success',
          text: t(`input.success.${type}`, {
            period: promoCodePeriod,
          }),
        });
      } else {
        setStatus({
          type: 'error',
          text: t(`input.error.${response.error.code}`),
        });
      }
    } catch (e) {
      logger.error(e);
      setPromoCodeCalculateResponse(null);
      setStatus({
        type: 'error',
        text: t(`input.error.unknown`),
      });
    }
  };

  const onChangeInputHandler = (e: ChangeEvent<HTMLInputElement>) => {
    setStatus(null);
    setPromoCodeCalculateResponse(null);
    setValue(e.target.value);
  };

  return (
    <>
      <div className={s.body}>
        {isInputVisible ? (
          <div className={s.row}>
            <Input
              name={'promo-code'}
              value={value}
              onChange={onChangeInputHandler}
              message={status ?? undefined}
              placeholder={t('input.placeholder')}
            />
            <Button
              size={'default'}
              color={'secondary'}
              onClick={checkPromoHandler}
              disabled={isDisabledButton}
            >
              {t('btn-text')}
            </Button>
          </div>
        ) : (
          <button className={s.text} onClick={showInputHandler}>
            {t('text')}
          </button>
        )}
      </div>
    </>
  );
};
