import { useCallback, useRef, useState } from 'react';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { getNewPaymentLink } from '@popup/project/youboost/components/PaymentContent/utils';
import { getMetaApiData } from '@utils/metaApiData';
import { usePaymentMethods } from './usePaymentMethods';
import { usePublicOfferUrl } from './usePublicOfferUrl';
import { logger } from '@utils/logger';
import { CreateNewPaymentLinkDto } from '@api/premium/createNewPaymentLink';
import { CreateNewPaymentLinkResponse } from '@api/premium/createNewPaymentLink/types';

export type HandlePaymentClickType = ({
  tariffName,
  paymentMethod,
  isAutoRenew,
  promocode,
}: Omit<
  CreateNewPaymentLinkDto,
  'url' | 'userId' | 'platform'
>) => Promise<CreateNewPaymentLinkResponse>;

export function usePaymentScreen() {
  const [error, setError] = useState<string | null>(null);

  const availablePaymentMethods = usePaymentMethods();
  const publicOfferUrl = usePublicOfferUrl();
  let userIdRef = useRef<string | undefined>();

  const handlePaymentClick: HandlePaymentClickType = useCallback(
    async ({ tariffName, paymentMethod, isAutoRenew, promocode }) => {
      try {
        const [{ apiBaseUrl: url }, { userId }] = await Promise.all([
          getMetaApiData(),
          getLocalStorageData([LocalStorageKey.UserId]),
        ]);
        userIdRef.current = userId;

        return getNewPaymentLink({
          paymentMethod,
          tariffName,
          url,
          userId,
          isAutoRenew,
          promocode,
        });
      } catch (error) {
        setError((error as Error)?.message || 'Ошибка при оплате');
        logger.error('usePaymentScreen: error', error);
        throw error;
      }
    },
    [],
  );

  return {
    error,
    availablePaymentMethods,
    publicOfferUrl,
    onPaymentClick: handlePaymentClick,
  };
}
