import { type Runtime } from 'webextension-polyfill';
import { browser_api } from '@app/browser_api';
import { isValidMessage } from '@app/messages/shared';
import { logger } from '@utils/logger';
import type {
  ActionTypes,
  MessageHandler,
  MessageTypes,
  ActionResponseMapTypes,
} from './types';

class MessageDispatcher {
  private handlers: Map<ActionTypes, Set<MessageHandler<any>>> = new Map();

  constructor() {
    browser_api.runtime.onMessage.addListener(((
      message,
      sender,
      sendResponse,
    ) => {
      this.dispatch(message, sender).then(sendResponse);
      return true;
    }) satisfies Runtime.OnMessageListenerCallback);
  }

  public register<T extends ActionTypes>(
    action: T,
    handler: MessageHandler<T>,
  ) {
    if (!this.handlers.has(action)) {
      this.handlers.set(action, new Set());
    }
    this.handlers.get(action)!.add(handler);
  }

  public unregister<T extends ActionTypes>(
    action: T,
    handler: MessageHandler<T>,
  ) {
    const result = this.handlers.get(action)?.delete(handler);
    if (result === false) {
      logger.error('unregister handler error:', { action, handler });
      console.error('unregister handler error:', { action, handler });
    }
  }

  private async dispatch(message: unknown, sender: Runtime.MessageSender) {
    if (!isValidMessage(message)) return;
    const action = message.action;
    if (!this.handlers.has(action)) {
      return { status: 'unhandled' };
    }

    const handlers = this.handlers.get(action)!;
    const results = [];

    for (const handler of handlers) {
      try {
        results.push(await handler(message, sender));
      } catch (error) {
        logger.error(`Error in handler for ${action}:`, error);
      }
    }

    // Возвращаем результат первого отработавшего обработчика
    return results[0];
  }

  public async send<T extends ActionTypes>(
    message: Extract<MessageTypes, { action: T }>,
  ): Promise<ActionResponseMapTypes[T]> {
    try {
      const response = await browser_api.runtime.sendMessage(message);

      return response as ActionResponseMapTypes[T];
    } catch (error) {
      logger.error(`Error sending message ${message.action}:`, error);
      throw error;
    }
  }
}

export const messageDispatcher = new MessageDispatcher();
