import { FC, useCallback, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { SettingsItem } from '@popup/project/youboost/components/SettingsContent/ui/SettingsItem/SettingsItem';
import { BaseOption } from '@popup/project/youboost/components/shared/Dropdown/types';
import { supportedLngs } from '@popup/shared/utils/i18n/languages';
import styles from './SettingsList.module.css';
import { usePremiumData } from '@popup/shared/hooks/usePremiumData';
import { CopyButton } from '../../../shared/CopyButton/ui/CopyButton';
import { Copy } from '../../../shared/icons/Copy/Copy';
import { DebugButton } from '../../../shared/DebugButton';
import { useLocalStorage } from '@popup/shared/hooks/useLocalStorage';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { useTheme } from '@popup/shared/contexts/Theme';
import { getModeValues } from '@popup/project/youboost/components/SettingsContent/utils/getModeValues';
import { ModeOptionType } from '@popup/project/youboost/components/SettingsContent/types';

interface Props {
  'data-testid'?: string;
}

export const SettingsList: FC<Props> = ({ 'data-testid': dataTestId }) => {
  const { t, i18n } = useTranslation('youboost', {
    keyPrefix: 'settings-page',
  });
  const { userId, hasPremium } = usePremiumData();
  const [deviceId] = useLocalStorage(LocalStorageKey.DeviceId);
  const [mode, setMode] = useLocalStorage(
    LocalStorageKey.YouboostAllInternetMode,
  );
  const { theme, possibleThemes, switchTheme } = useTheme();

  const currentLocale = i18n.language;

  const onLangChange = (newValue: BaseOption | null) => {
    if (!newValue) return;
    const { value } = newValue;
    void i18n.changeLanguage(value);
  };

  const onQualityChange = (newValue: BaseOption | null) => {
    if (!newValue) return;
    const { value, label } = newValue;
    //   TODO FRO-676 добавить обработчик смены качества видео
  };

  const onThemeChange = (newValue: BaseOption | null) => {
    if (!newValue) return;
    const { value } = newValue;
    void switchTheme(value);
  };

  const onModeChange = useCallback(
    (newValue: ModeOptionType | null) => {
      if (!newValue) return;
      const { value } = newValue;
      void setMode(value);
    },
    [setMode],
  );

  const langList = useMemo(
    () =>
      supportedLngs.map((item) => ({
        label: t(`lang-${item}`),
        value: item,
        'data-testid': `dropdown-btn-${item}`,
      })),
    [t],
  );

  const themeList = useMemo(
    () =>
      possibleThemes.map((item) => ({
        label: t(`theme-${item}`),
        value: item,
        'data-testid': `dropdown-btn-${item}`,
      })),
    [t, possibleThemes],
  );

  const modes = useMemo(() => getModeValues({ t }), [t]);

  const currentMode = mode ?? (currentLocale === 'ru' ? 'smart' : 'direct');

  return (
    <div className={styles.list} data-testid={dataTestId}>
      <SettingsItem<BaseOption>
        data-testid={'list-item-1'}
        i18nKey={'list-item-1'}
        dropdownProps={{
          onChange: onLangChange,
          options: langList,
          value: langList.find(({ value }) => value === currentLocale),
        }}
      />
      {/*TODO FRO-676 добавить секцию со сменой качества видео*/}
      {/*<SettingsItem<BaseOption>*/}
      {/*  i18nKey={'list-item-2'}*/}
      {/*  dropdownProps={{*/}
      {/*    onChange: onQualityChange,*/}
      {/*    options: [*/}
      {/*      { label: '4K', value: '4k' },*/}
      {/*      { label: '1080p', value: '1080p' }*/}
      {/*    ]*/}
      {/*  }}*/}
      {/*/>*/}
      <SettingsItem<BaseOption>
        data-testid={'list-item-3'}
        i18nKey={'list-item-3'}
        dropdownProps={{
          onChange: onThemeChange,
          options: themeList,
          value: themeList.find(({ value }) => value === theme),
        }}
        isDisabled={!hasPremium}
      />
      {userId && (
        <>
          <SettingsItem<ModeOptionType>
            data-testid={'list-item-7'}
            i18nKey={'list-item-7'}
            dropdownProps={{
              onChange: onModeChange,
              options: modes,
              value: modes.find(({ value }) => value === currentMode),
            }}
            isDisabled={!hasPremium}
          />
          <SettingsItem<BaseOption>
            data-testid={'list-item-4'}
            i18nKey={'list-item-4'}
          >
            <div>
              <CopyButton
                size={'default'}
                color={'tertiary'}
                textToCopy={userId}
              >
                <span className={styles['copy-text']}>
                  {userId} <Copy className={styles.icon} />
                </span>
              </CopyButton>
            </div>
          </SettingsItem>
        </>
      )}
      {deviceId && (
        <SettingsItem<BaseOption>
          data-testid={'list-item-5'}
          i18nKey={'list-item-5'}
        >
          <div>
            <CopyButton
              size={'default'}
              color={'tertiary'}
              textToCopy={deviceId}
            >
              <span className={styles['copy-text']}>
                {deviceId.slice(0, 8)} <Copy className={styles.icon} />
              </span>
            </CopyButton>
          </div>
        </SettingsItem>
      )}
      <SettingsItem<BaseOption>
        data-testid={'list-item-6'}
        i18nKey={'list-item-6'}
      >
        <div>
          <DebugButton
            text={
              <span className={styles['debug-button']}>
                {t('debug-button')} <Copy className={styles.icon} />
              </span>
            }
          />
        </div>
      </SettingsItem>
    </div>
  );
};
