import { FC, useEffect } from 'react';
import { Outlet, useNavigate, To } from 'react-router-dom';
import { Actions } from '@app/actions/shared';
import { messageDispatcher } from '@app/infrastructure/messageDispatcher';
import { MessageHandler } from '@app/infrastructure/types';

interface Props {}

export const NavigationLayout: FC<Props> = ({}) => {
  const navigate = useNavigate();

  useEffect(() => {
    const listener: MessageHandler<Actions.NavigateToPath> = (message) => {
      const payload = message.payload;
      if (typeof payload === 'string') {
        navigate(payload);
      } else {
        const { pathname, state } = payload;
        navigate(pathname, { state });
      }
      return { hasActiveListener: true };
    };
    messageDispatcher.register(Actions.NavigateToPath, listener);
    return () => messageDispatcher.unregister(Actions.NavigateToPath, listener);
  }, [navigate]);

  return <Outlet />;
};
