import { useEffect, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { fetchTariffs } from '@api/premium/fetchTariffs';
import { getFetchTariffsApiUrl, type FetchTariffsResponse } from '@api/urls';
import { useGetDiscountPrice } from '@popup/project/youboost/hooks/useGetDiscountPrice';
import { getMetaApiData } from '@utils/metaApiData';
import { logger } from '@utils/logger';

type TariffsHookValues = {
  isTariffError: boolean;
  isTariffsLoading: boolean;
  tariffs: FetchTariffsResponse | undefined;
  discountPrice: number | undefined;
};

export function useTariffs(): TariffsHookValues {
  const { i18n } = useTranslation();
  const [tariffs, setTariffs] = useState<FetchTariffsResponse | undefined>();
  const [isTariffsLoading, setIsTariffsLoading] = useState<boolean>(true);
  const [isTariffError, setIsTariffError] = useState<boolean>(false);
  const { discountPrice } = useGetDiscountPrice();

  useEffect(() => {
    async function fetchAllTariffs(): Promise<void> {
      try {
        setIsTariffsLoading(true);
        const { apiBaseUrl, rubleToEuroRate } = await getMetaApiData();
        const data = await fetchTariffs(getFetchTariffsApiUrl(apiBaseUrl));
        if (data.length === 0) {
          throw new Error('Tariffs data is empty');
        }
        setTariffs(data);
      } catch (error) {
        logger.error('useTariffs: Error in fetchAllTariffs:', error);
        setIsTariffError(true);
      } finally {
        setIsTariffsLoading(false);
      }
    }

    void fetchAllTariffs();
  }, [i18n.language]);

  return {
    isTariffError,
    isTariffsLoading,
    tariffs,
    discountPrice,
  };
}
