import { httpClient } from '@api/httpClient';
import { getActivatePromocodeApiUrl } from '@api/urls';
import { getMetaApiData } from '@utils/metaApiData';
import { HTTPError } from 'ky';
import type {
  ActivatePromoCodeResponseType,
  ActivatePromoCodeType,
} from './types';

export const activatePromoCode: ActivatePromoCodeType = async (body) => {
  try {
    const { apiBaseUrl } = await getMetaApiData();
    const cancelSubscriptionApiUrl = getActivatePromocodeApiUrl(apiBaseUrl);
    return await httpClient
      .post<ActivatePromoCodeResponseType>(cancelSubscriptionApiUrl, {
        json: body,
      })
      .json();
  } catch (e) {
    if (e instanceof HTTPError) {
      return await e.response.json<
        Extract<ActivatePromoCodeResponseType, { data: null }>
      >();
    }
    return {
      data: null,
      error: { code: 'unknown', localized_message: 'Unknown error' },
    };
  }
};
