import { FC, MutableRefObject } from 'react';
import { Button } from '@popup/project/youboost/components/shared/Button';
import { Trans, useTranslation } from 'react-i18next';
import { PaymentMethodV2Type } from '@app/features/types/paymentMethodTypes';
import { TariffData } from '@api/urls';
import type { HandlePaymentClickType } from '@popup/project/youboost/components/PaymentContent/hooks/usePaymentScreen';
import { logger } from '@utils/logger';
import { browser_api } from '@app/browser_api';
import {
  type PromoCodeCalculateResponseType,
  getPromoFlags,
} from '@api/promoCodeCalculate';
import { useNavigate } from 'react-router-dom';
import { RoutePath } from '@popup/project/youboost/routes/types/RoutePath';
import { useFormatPrice } from '@popup/project/youboost/hooks/useFormatPrice';

import s from './Footer.module.css';
import { activatePromoCode } from '@api/activatePromoCode';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { getLocalStorageData } from '@app/storage/local/shared';
import { getSubscriptionInfo } from '@utils/getSubscriptionInfo';

interface Props extends TariffData {
  publicOfferUrl: string;
  selectedPaymentMethodRef: MutableRefObject<PaymentMethodV2Type | null>;
  renewalEnabledRef: MutableRefObject<boolean>;
  handlePaymentClick: HandlePaymentClickType;
  promoCodeCalculateResponse: PromoCodeCalculateResponseType | null;
}

export const Footer: FC<Props> = ({
  tariff,
  price,
  selectedPaymentMethodRef,
  renewalEnabledRef,
  handlePaymentClick,
  publicOfferUrl,
  promoCodeCalculateResponse,
}) => {
  const navigate = useNavigate();
  const { t } = useTranslation('youboost', {
    keyPrefix: 'payment-page.footer',
  });
  const formatPrice = useFormatPrice();

  const amount = formatPrice(price);
  const { isFreeUsageGift } = getPromoFlags(promoCodeCalculateResponse);

  const clickHandler = async () => {
    try {
      const paymentMethod = selectedPaymentMethodRef.current;
      const isAutoRenew = paymentMethod?.supportsAutoRenew
        ? renewalEnabledRef.current
        : false;
      if (!paymentMethod) return;

      const promoCodeDetails =
        promoCodeCalculateResponse?.data?.details?.promocode;

      if (isFreeUsageGift && promoCodeDetails) {
        const { userId } = await getLocalStorageData(LocalStorageKey.UserId);

        if (!userId) {
          throw new Error('User ID is not defined.');
        }

        const response = await activatePromoCode({
          promocode: promoCodeDetails.code,
          userId,
        });
        if (response.data?.activated) {
          await getSubscriptionInfo();
          navigate({
            pathname: RoutePath.PromoCodeActivated,
            search: `?interval=${promoCodeDetails.interval ?? ''}`,
          });
        }
        return;
      }

      const response = await handlePaymentClick({
        paymentMethod: paymentMethod.type,
        isAutoRenew,
        tariffName: tariff,
        promocode: promoCodeDetails?.code,
      });

      await browser_api.tabs.create({ url: response.paymentLink });
      window.close();
    } catch (e) {
      logger.error('Footer: error', e);
    }
  };

  const termsClickHandler = async () => {
    await browser_api.tabs.create({ url: publicOfferUrl });
  };

  return (
    <div className={s.box}>
      <Button size={'default'} color={'primary'} onClick={clickHandler}>
        {isFreeUsageGift ? t('activate-button') : t('pay-button', { amount })}
      </Button>
      <div className={s.description}>
        <Trans
          t={t}
          i18nKey="description"
          components={{
            button: (
              <button
                type="button"
                data-testid="terms-button"
                onClick={termsClickHandler}
              />
            ),
          }}
        />
      </div>
    </div>
  );
};
