import { useEffect, useRef } from 'react';
import { Actions } from '@app/actions/shared';
import { messageDispatcher } from '@app/infrastructure/messageDispatcher';

export function usePopupReady(): void {
  const isMessageSent = useRef(false);

  useEffect(() => {
    if (!isMessageSent.current) {
      void messageDispatcher.send({
        action: Actions.PopupReady,
      });
      isMessageSent.current = true;
    }
  }, []);
}
