import { useTranslation } from 'react-i18next';
import { MODE_VALUES } from '../constants';
import { ModeOptionType } from '../types';

export const getModeValues = ({
  t,
}: {
  t: ReturnType<typeof useTranslation>['t'];
}): Array<ModeOptionType & { 'data-testid': string }> =>
  MODE_VALUES.map((item) => ({
    label: t(`mode-${item}`),
    value: item,
    'data-testid': `mode-${item}`,
  }));
