import { useTranslation } from 'react-i18next';
import { Button } from '@popup/project/youboost/components/shared/Button';
import styles from './FooterButtons.module.css';
import { useNavigate } from 'react-router-dom';
import { RoutePath } from '@popup/project/youboost/routes/types/RoutePath';
import { getSubscriptionInfo } from '@utils/getSubscriptionInfo';

interface Props {
  cancelHandler: () => Promise<void>;
}

export const FooterButtons = ({ cancelHandler }: Props) => {
  const { t } = useTranslation('youboost', {
    keyPrefix: 'premium-sale-persuasion.actions',
  });

  const navigate = useNavigate();

  const continueHandler = async () => {
    const subscriptionInfo = await getSubscriptionInfo();
    if (!subscriptionInfo) {
      throw new Error('No subscription found');
    }

    if (!subscriptionInfo.data.subscription.botDeepLink) {
      await cancelHandler();
      return;
    }

    navigate(RoutePath.TelegramAuthPromo);
  };

  return (
    <div className={styles.buttons}>
      <Button color="tertiary" size="default" onClick={continueHandler}>
        {t('continue')}
      </Button>
      <Button
        color="primary"
        size="big"
        onClick={() =>
          navigate(RoutePath.Tariffs, { state: { hasOneMonthDiscount: true } })
        }
      >
        {t('activate-discount')}
      </Button>
    </div>
  );
};
