import { Button } from '@popup/project/youboost/components/shared/Button';
import { TelegramPromo } from './TelegramPromo';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';

import styles from './Footer.module.css';
import { RoutePath } from '@popup/project/youboost/routes/types/RoutePath';
import clsx from 'clsx';
import { getLocalStorageData } from '@app/storage/local/shared';
import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import { TWELVE_HOURS_MS } from '@utils/proxy/constants';
import { useFeaturesList } from '@app/features/hooks/useFeaturesList';
import { Feature } from '@app/features/types/Feature';
import { browser_api } from '@app/browser_api';
import { useLocalStorage } from '@popup/shared/hooks/useLocalStorage';

interface Props {
  className?: string;
}

export function Footer({ className }: Props): JSX.Element {
  const navigate = useNavigate();
  const { t } = useTranslation('youboost', { keyPrefix: 'footer' });
  const { featuresList } = useFeaturesList();
  const isRedButtonVisible = featuresList[Feature.RedButton];

  const [metaApiData] = useLocalStorage(LocalStorageKey.MetaApiData);
  const [currentLocale] = useLocalStorage(LocalStorageKey.CurrentLocale);

  const handleClickHelp = async () => {
    try {
      const { isAllInternetProxy } = await getLocalStorageData(
        LocalStorageKey.IsAllInternetProxy,
      );

      const lastKey = isAllInternetProxy
        ? LocalStorageKey.LastManualServerChangeAtAllInternet
        : LocalStorageKey.LastManualServerChangeAtYoutube;

      const { [lastKey]: lastChangedAt } = await getLocalStorageData(lastKey);

      const shouldOpenChangeServer =
        typeof lastChangedAt !== 'number' ||
        Date.now() - lastChangedAt >= TWELVE_HOURS_MS;

      navigate(
        shouldOpenChangeServer ? RoutePath.ChangeServer : RoutePath.Support,
      );
    } catch (_) {
      navigate(RoutePath.ChangeServer);
    }
  };
  const redButtonHandler = async () => {
    const redButtonConfig = metaApiData?.redButton;
    if (!redButtonConfig) return;
    await browser_api.tabs.create({
      url:
        currentLocale === 'ru'
          ? redButtonConfig.ru.url
          : redButtonConfig.en.url,
    });
  };

  return (
    <div className={clsx(styles.footer, className)} data-testid="footer">
      <Button onClick={handleClickHelp} size="small" color="tertiary">
        {t('help')}
      </Button>
      {isRedButtonVisible && metaApiData?.redButton ? (
        <Button onClick={redButtonHandler} size="small" color="secondary">
          {currentLocale === 'ru'
            ? metaApiData.redButton.ru.text
            : metaApiData.redButton.en.text}
        </Button>
      ) : (
        <TelegramPromo />
      )}
    </div>
  );
}
