import { FC } from 'react';
import { Logo } from '@popup/project/youboost/components/shared/Logo';
import { RoutePath } from '@popup/project/youboost/routes/types/RoutePath';
import { Trans, useTranslation } from 'react-i18next';
import { SecondaryWrapper } from '@popup/project/youboost/components/shared/SecondaryWrapper';
import { useNavigate } from 'react-router-dom';
import {
  AuthBox,
  Footer,
} from '@popup/project/youboost/components/TelegramAuthPromoContent';
import { Error } from '@popup/project/youboost/components/shared/errors/Error';
import { useSetupTariffFree } from '@popup/shared/hooks/useSetupTariffFree';
import { usePremiumData } from '@popup/shared/hooks/usePremiumData';
import s from './TelegramAuthPromo.module.css';
import { logger } from '@utils/logger';

interface Props {}

export const TelegramAuthPromo: FC<Props> = ({}) => {
  const navigate = useNavigate();
  const { t } = useTranslation('youboost', {
    keyPrefix: 'telegram-auth-promo-page',
  });
  const { botDeepLink: url } = usePremiumData();
  const { becomeFreeUserHandler, error } = useSetupTariffFree();

  if (!url) {
    return null;
  }

  if (error) {
    return (
      <Error
        text={t(`error.${error}`)}
        onClose={() => {
          navigate(RoutePath.Root);
        }}
      />
    );
  }

  const cancelHandler = async () => {
    try {
      const data = await becomeFreeUserHandler();
      if (data) {
        navigate(RoutePath.Root, { replace: true });
      }
    } catch (e) {
      logger.error('TelegramAuthPromo: cancelHandler error', e);
    }
  };

  return (
    <SecondaryWrapper
      header={t('header')}
      footer={<Footer cancelHandler={cancelHandler} />}
      closeClickHandler={() => navigate(RoutePath.Root)}
    >
      <div className={s.body}>
        <div className={s.top}>
          <Logo className={s.logo} />
          <div className={s.title}>
            <Trans t={t} i18nKey="title" components={{ span: <span /> }} />
          </div>
        </div>
        <AuthBox url={url} cancelHandler={cancelHandler} />
      </div>
    </SecondaryWrapper>
  );
};
