import { LocalStorageKey } from '@app/storage/local/types/sharedTypes';
import {
  deleteLocalStorageData,
  getLocalStorageData,
} from '@app/storage/local/shared';
import type { InitialEntry } from './types';

export const getAndClearInitialEntry = async (
  defaultPath: string,
): Promise<InitialEntry> => {
  const { popupInitialEntry } = await getLocalStorageData(
    LocalStorageKey.PopupInitialEntry,
  );
  if (popupInitialEntry) {
    await deleteLocalStorageData(LocalStorageKey.PopupInitialEntry);
    return popupInitialEntry;
  }
  return defaultPath;
};
