import { Tariff } from '@api/premium/types/Tariff';

type ErrorType = {
  code: 'promocode_error' | 'user_not_found' | 'tariff_invalid' | 'unknown';
  localized_message: string;
};

type SuccessResponseType = {
  data: PromoCodeCalculateDataType;
  error: null;
};

type UnsuccessResponseType = {
  data: null;
  error: ErrorType;
};

export type PromoCodeCalculateResponseType =
  | SuccessResponseType
  | UnsuccessResponseType;

export type PromoCodeCalculateDtoType = {
  tariff: Tariff;
  promocode: string;
  userId: string;
};

export type PromoCodeCalculateType = (
  args: PromoCodeCalculateDtoType,
) => Promise<PromoCodeCalculateResponseType>;

export type PromoCodeCalculateDataType = {
  requires_payment: boolean;
  activated: boolean;
  details: CheckoutDetailsBase;
};

type PromoCodeApplicabilityType = 'first_payment_only' | 'forever';

export type CheckoutDetailsBase = {
  total_to_pay: string;
  plan_price: string;
  paid_until: string | null;
  promocode: PayPromoCode | null;
};

export type PayPromoCode = {
  type: string;
  code: string;
  applicability_type: PromoCodeApplicabilityType;

  value: string | null;
  interval: string | null;
  plan_id: number | null;
};

export interface PromoFlags {
  isPercentDiscount: boolean;
  isExtraDays: boolean;
  isFreeUsageGift: boolean;
}

export type ParsedInterval = {
  years: number;
  days: number;
};

export type PluralFn = (
  key: 'day' | 'year',
  count: number,
  adjective?: string,
) => string;

export const isSuccessResponse = (
  response: PromoCodeCalculateResponseType | null,
): response is SuccessResponseType => {
  return (
    response !== null &&
    typeof response.data === 'object' &&
    response.data !== null
  );
};

export type AdjectiveConfig = {
  key: string;
  t: (key: string, options?: { count: number }) => string;
};
