import { FC } from 'react';
import { useTheme } from '@popup/shared/contexts/Theme';
import { DarkLogo } from '@popup/project/youboost/components/shared/icons/DarkLogo/DarkLogo';
import { LightLogo } from '@popup/project/youboost/components/shared/icons/LightLogo/LightLogo';

interface Props {
  className: string;
}

export const Logo: FC<Props> = ({ className }) => {
  const { theme } = useTheme();

  if (theme === 'premium') {
    return <DarkLogo className={className} />;
  }

  return <LightLogo className={className} />;
};
