import { useState } from 'react';
import {
  defaultPriceRu,
  discountPriceRu,
} from '@popup/project/youboost/components/TariffsContent/constants';

export const useGetDiscountPrice = () => {
  const [discountPrice] = useState<number>(discountPriceRu);
  const [price] = useState<number>(defaultPriceRu);

  return {
    price,
    discountPrice,
  };
};
