import {
  isSuccessResponse,
  PromoCodeCalculateResponseType,
  PromoFlags,
  ParsedInterval,
  PluralFn,
  AdjectiveConfig,
} from './types';
import { normalizeMoney } from '@utils/normalizeMoney';

export const getPromoFlags = (
  response: PromoCodeCalculateResponseType | null,
): PromoFlags => {
  if (!isSuccessResponse(response)) {
    return {
      isPercentDiscount: false,
      isExtraDays: false,
      isFreeUsageGift: false,
    };
  }
  const responseData = response.data;
  const details = responseData.details;
  const promoCodeData = details.promocode;

  const isPercentDiscount = promoCodeData?.value !== null;
  const isExtraDays = promoCodeData?.interval !== null;

  const isFreeUsageGift =
    isExtraDays &&
    normalizeMoney(details.total_to_pay) === 0 &&
    !responseData.requires_payment;

  return {
    isPercentDiscount,
    isExtraDays,
    isFreeUsageGift,
  };
};

export const parseInterval = (
  interval: string | null | undefined,
): ParsedInterval => {
  if (!interval) return { years: 0, days: 0 };
  const match = interval.match(/^P(?:(\d+)Y)?(?:(\d+)D)?$/);
  if (!match) return { years: 0, days: 0 };
  const [, years, days] = match;
  return {
    years: years ? Number(years) : 0,
    days: days ? Number(days) : 0,
  };
};

export const formatIntervalPeriod = (
  interval: string | null | undefined,
  plural: PluralFn,
  adjective?: AdjectiveConfig,
): string => {
  const { years, days } = parseInterval(interval);

  const parts: string[] = [];

  const hasYears = years > 0;
  const hasDays = days > 0;

  const shouldApplyAdjToYears = hasYears && !hasDays;

  if (hasYears) {
    parts.push(
      plural(
        'year',
        years,
        shouldApplyAdjToYears
          ? adjective?.t(`${adjective.key}.${adjective.key}`, { count: years })
          : undefined,
      ),
    );
  }

  if (hasDays) {
    parts.push(
      plural(
        'day',
        days,
        adjective?.t(`${adjective.key}.${adjective.key}`, { count: days }),
      ),
    );
  }

  return parts.join(' ');
};
